import{c as r,Q as a,j as o,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"The Decoder — 2026-05-10","description":"","frontmatter":{"title":"The Decoder — 2026-05-10","date":"2026-05-10T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-10-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-10-the-decoder.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-05/2026-05-10-the-decoder.md"};function i(n,e,h,d,l,c){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="🔓-the-decoder-—-2026-05-10" tabindex="-1">🔓 The Decoder — 2026-05-10 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-10" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-10&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="fields-medalist-says-chatgpt-5-5-pro-delivered-phd-level-math-research-in-under-two-hours-with-zero-human-help" tabindex="-1"><a href="https://the-decoder.com/fields-medalist-says-chatgpt-5-5-pro-delivered-phd-level-math-research-in-under-two-hours-with-zero-human-help/" target="_blank" rel="noreferrer">Fields Medalist says ChatGPT 5.5 Pro delivered &quot;PhD-level&quot; math research in under two hours with zero human help</a> <a class="header-anchor" href="#fields-medalist-says-chatgpt-5-5-pro-delivered-phd-level-math-research-in-under-two-hours-with-zero-human-help" aria-label="Permalink to &quot;[Fields Medalist says ChatGPT 5.5 Pro delivered &quot;PhD-level&quot; math research in under two hours with zero human help](https://the-decoder.com/fields-medalist-says-chatgpt-5-5-pro-delivered-phd-level-math-research-in-under-two-hours-with-zero-human-help/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-09</em></p><p>Fields Medalist Timothy Gowers had ChatGPT 5.5 Pro tackle open problems in number theory. The model improved an exponential bound to a polynomial one in under an hour. An MIT researcher involved calls the key idea &quot;completely original.&quot; Gowers&#39; takeaway: the bar for mathematical contributions is now proving something LLMs can&#39;t.</p><p>The article <a href="https://the-decoder.com/fields-medalist-says-chatgpt-5-5-pro-delivered-phd-level-math-research-in-under-two-hours-with-zero-human-help/" target="_blank" rel="noreferrer">Fields Medalist says ChatGPT 5.5 Pro delivered &quot;PhD-level&quot; math research in under two hours with zero human help</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="broadcom-reportedly-won-t-build-openai-s-custom-chip-unless-microsoft-buys-40-percent-of-them" tabindex="-1"><a href="https://the-decoder.com/broadcom-reportedly-wont-build-openais-custom-chip-unless-microsoft-buys-40-percent-of-them/" target="_blank" rel="noreferrer">Broadcom reportedly won&#39;t build OpenAI&#39;s custom chip unless Microsoft buys 40 percent of them</a> <a class="header-anchor" href="#broadcom-reportedly-won-t-build-openai-s-custom-chip-unless-microsoft-buys-40-percent-of-them" aria-label="Permalink to &quot;[Broadcom reportedly won&#39;t build OpenAI&#39;s custom chip unless Microsoft buys 40 percent of them](https://the-decoder.com/broadcom-reportedly-wont-build-openais-custom-chip-unless-microsoft-buys-40-percent-of-them/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-09</em></p><p>OpenAI&#39;s custom AI chip project with Broadcom has hit a funding wall. Broadcom won&#39;t finance production unless Microsoft commits to buying 40 percent of the chips, and Microsoft hasn&#39;t agreed yet. OpenAI manager Sachin Katti called the dependency &quot;financially unattractive&quot; in an internal message. The first phase alone costs around 18 billion dollars.</p><p>The article <a href="https://the-decoder.com/broadcom-reportedly-wont-build-openais-custom-chip-unless-microsoft-buys-40-percent-of-them/" target="_blank" rel="noreferrer">Broadcom reportedly won&#39;t build OpenAI&#39;s custom chip unless Microsoft buys 40 percent of them</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="google-s-preferred-sources-feature-is-a-free-pass-for-more-garbage-in-search" tabindex="-1"><a href="https://the-decoder.com/googles-preferred-sources-feature-is-a-free-pass-for-more-garbage-in-search/" target="_blank" rel="noreferrer">Google&#39;s &quot;Preferred Sources&quot; feature is a free pass for more garbage in search</a> <a class="header-anchor" href="#google-s-preferred-sources-feature-is-a-free-pass-for-more-garbage-in-search" aria-label="Permalink to &quot;[Google&#39;s &quot;Preferred Sources&quot; feature is a free pass for more garbage in search](https://the-decoder.com/googles-preferred-sources-feature-is-a-free-pass-for-more-garbage-in-search/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-09</em></p><p>Google frames &quot;Preferred Sources&quot; as a way to bring more quality journalism into search. In practice, it shifts responsibility to a manual setting almost no one will use. That gives Google a user-choice argument for users and regulators while it keeps sidelining the open web in favor of its own AI interfaces.</p><p>The article <a href="https://the-decoder.com/googles-preferred-sources-feature-is-a-free-pass-for-more-garbage-in-search/" target="_blank" rel="noreferrer">Google&#39;s &quot;Preferred Sources&quot; feature is a free pass for more garbage in search</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="pseudoscientific-emotion-ai-is-invading-the-workplace-an-atlantic-report-shows" tabindex="-1"><a href="https://the-decoder.com/pseudoscientific-emotion-ai-is-invading-the-workplace-an-atlantic-report-shows/" target="_blank" rel="noreferrer">Pseudoscientific emotion AI is invading the workplace, an Atlantic report shows</a> <a class="header-anchor" href="#pseudoscientific-emotion-ai-is-invading-the-workplace-an-atlantic-report-shows" aria-label="Permalink to &quot;[Pseudoscientific emotion AI is invading the workplace, an Atlantic report shows](https://the-decoder.com/pseudoscientific-emotion-ai-is-invading-the-workplace-an-atlantic-report-shows/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-09</em></p><p>Software that claims to read human emotions using AI is quietly becoming a fixture of everyday work life, Ellen Cushing reports in a feature for The Atlantic.</p><p>The article <a href="https://the-decoder.com/pseudoscientific-emotion-ai-is-invading-the-workplace-an-atlantic-report-shows/" target="_blank" rel="noreferrer">Pseudoscientific emotion AI is invading the workplace, an Atlantic report shows</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks" tabindex="-1"><a href="https://the-decoder.com/ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks/" target="_blank" rel="noreferrer">AI money keeps flowing as Deepseek plans record raise and Core Automation quadruples valuation in weeks</a> <a class="header-anchor" href="#ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks" aria-label="Permalink to &quot;[AI money keeps flowing as Deepseek plans record raise and Core Automation quadruples valuation in weeks](https://the-decoder.com/ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-08</em></p><p>Deepseek is planning a funding round of up to $7.35 billion, the largest ever for a Chinese AI company. Deepseek V4.1 is set to launch in June. Meanwhile, Core Automation, founded by ex-OpenAI researcher Jerry Tworek just six weeks ago, is already targeting a $4 billion valuation.</p><p>The article <a href="https://the-decoder.com/ai-money-keeps-flowing-as-deepseek-plans-record-raise-and-core-automation-quadruples-valuation-in-weeks/" target="_blank" rel="noreferrer">AI money keeps flowing as Deepseek plans record raise and Core Automation quadruples valuation in weeks</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const m=r(s,[["render",i]]);export{u as __pageData,m as default};
